\begin{align*}
	A &= \sin^4 \alpha + \cos^4 \alpha + 2 \sin^2 \alpha \cdot \cos^2 \alpha \\
	A &= \left(\sin^2 \alpha\right)^2 + 2 \sin^2 \alpha \cdot \cos^2 \alpha + \left(\cos^2 \alpha\right)^2 \\
